+inline py::dict mergeResultToDict(const MergeResult& r)
+{
+  py::dict d;
+  d["success"] = r.success;
+  d["output_path"] = r.output_path.string();
+  d["segments_merged"] = r.segments_merged;
+  d["events_written"] = r.events_written;
+  d["bytes_written"] = r.bytes_written;
+  d["errors"] = r.errors;
